import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.3KapzJiJ.js";const u=JSON.parse('{"title":"Manual","description":"","frontmatter":{},"headers":[],"relativePath":"manual/index.md","filePath":"manual/index.md","lastUpdated":null}'),o={name:"manual/index.md"};function n(l,e,r,h,p,c){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="manual" tabindex="-1">Manual <a class="header-anchor" href="#manual" aria-label="Permalink to &quot;Manual&quot;">​</a></h1><p><code>SpeciesDistributionToolkit.jl</code> is a collection of packages for species distribution modeling and biodiversity research, for the <a href="https://julialang.org/" target="_blank" rel="noreferrer">Julia</a> programming language. It is built and maintained by the <em>Laboratoire d&#39;Écologie Prédictive et Interprétable pour la Crise de la Biodiversité</em> (<a href="https://epic-biodiversity.org/" target="_blank" rel="noreferrer">ÉPIC Biodiversity</a>).</p><div class="info custom-block"><p class="custom-block-title">Not just for research!</p><p>This package is now used in pipelines in <a href="https://boninabox.geobon.org/index" target="_blank" rel="noreferrer">BON in a Box</a>, <a href="https://geobon.org/" target="_blank" rel="noreferrer">GEOBON</a>&#39;s project to automate the calculation and representation of the post-2020 <a href="https://www.cbd.int/gbf" target="_blank" rel="noreferrer">GBF indicators</a>. See the <a href="https://boninabox.geobon.org/tool-detail?id=236" target="_blank" rel="noreferrer">BON in a Box tool page</a>.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>The package is published in the Julia general repository, and can be installed with:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-macchiato has-highlighted vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#C6A0F6;">import</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;"> Pkg</span></span>
<span class="line highlighted"><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">Pkg</span><span style="--shiki-light:#179299;--shiki-dark:#8BD5CA;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#8AADF4;--shiki-dark-font-style:italic;">add</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6DA95;">&quot;SpeciesDistributionToolkit&quot;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">) </span></span></code></pre></div><p>This will automatically install all the sub-packages.</p><h2 id="upgrades" tabindex="-1">Upgrades <a class="header-anchor" href="#upgrades" aria-label="Permalink to &quot;Upgrades&quot;">​</a></h2><p>To help with dependency management, we suggest that the <code>compat</code> entry in the <code>Project.toml</code> file of your project should be:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-macchiato vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#939AB7;">[</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">compat</span><span style="--shiki-light:#7C7F93;--shiki-dark:#939AB7;">]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">SpeciesDistributionToolkit </span><span style="--shiki-light:#179299;--shiki-dark:#8BD5CA;">=</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6DA95;"> &quot;1&quot;</span></span></code></pre></div><p>This will ensure that all releases of the <code>v1.x.x.</code> series will be compatible with your project. Because the modules all internally rely on this same compatibility rule, you can get the latest releases of everything with:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-macchiato has-highlighted vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#C6A0F6;">import</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;"> Pkg</span></span>
<span class="line highlighted"><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">Pkg</span><span style="--shiki-light:#179299;--shiki-dark:#8BD5CA;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#8AADF4;--shiki-dark-font-style:italic;">update</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CAD3F5;">() </span></span></code></pre></div><p>All version of the package that share a major version number (<code>1</code> for now) will <em>always</em> be fully interoperable, and maintain backwards compatibility.</p><h2 id="Contents-of-the-manual" tabindex="-1">Contents of the manual <a class="header-anchor" href="#Contents-of-the-manual" aria-label="Permalink to &quot;Contents of the manual {#Contents-of-the-manual}&quot;">​</a></h2><p>This section of the manual presents short capsules about getting you to achieve a simple, well-defined task. Although there is some discussion of design elements for the various packages, this is <em>not</em> the documentation; instead, you can think of this section as a collection of snippets to re-use to build your own analysis. The vignettes also introduce, when relevant, some variations around how to perform a given task. The documentation (and complete list of functions) for each component package is accessible through the <em>Ecosystem</em> tab in the navigation bar.</p><p>Most manual pages end with a list of the documentation of the most important functions used. The first two sections of the manual (use cases) are more fleshed out tutorials, that are meant to illustrate how the package works. It is not a terrible idea to read them first, and then to take a deeper dive into the more detailed explanations.</p><p>If you have a question about how to achieve a specific task, feel free to <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/discussions/categories/ideas" target="_blank" rel="noreferrer">share it</a> in the Discussion page, so we can add it to the manual.</p><h2 id="citation" tabindex="-1">Citation <a class="header-anchor" href="#citation" aria-label="Permalink to &quot;Citation&quot;">​</a></h2><p>If you use the package, please cite</p><blockquote><p>Poisot, T., Bussières-Fournel, A., Dansereau, G., and Catchen, M. D. (2025). A Julia toolkit for species distribution data. <em>Peer Community Journal</em> 5(e101). doi: <a href="https://peercommunityjournal.org/articles/10.24072/pcjournal.589/" target="_blank" rel="noreferrer">10.24072/pcjournal.589</a></p></blockquote><p>as well as</p><blockquote><p>Dansereau, G., and Poisot, T. (2021). SimpleSDMLayers.jl and GBIF.jl: A Framework for Species Distribution Modeling in Julia. <em>Journal of Open Source Software</em> 6(57), 2872, doi: <a href="https://doi.org/10.21105/joss.02872" target="_blank" rel="noreferrer">10.21105/joss.02872</a></p></blockquote>`,22)])])}const k=a(o,[["render",n]]);export{u as __pageData,k as default};
